# BEST PRACTICE: Hybrid Reranking Pattern with PII redaction
from typing import List, Dict
import hashlib

class CricketMatchRAG:
    def __init__(self, vector_db, access_control):
        self.vector_db = vector_db
        self.access_control = access_control
        self.pii_patterns = ['player_contact', 'salary_info', 'medical_records']

    def retrieve_and_redact(self, query: str, user_id: str) -> List[Dict]:
        # Stage 1: Coarse retrieval (fast, no filtering)
        candidates = self.vector_db.semantic_search(query, top_k=50)

        # Stage 2: Access control filtering
        permitted = [
            doc for doc in candidates 
            if self.access_control.can_access(user_id, doc['document_id'])
        ]

        # Stage 3: PII redaction
        redacted = []
        for doc in permitted[:10]:
            cleaned = self._redact_sensitive_fields(doc, user_id)
            redacted.append(cleaned)

        return redacted

    def _redact_sensitive_fields(self, document: Dict, user_id: str) -> Dict:
        """Remove or hash PII based on user clearance level"""
        clearance = self.access_control.get_clearance(user_id)
        redacted = document.copy()

        if clearance < 3:  # restricted access
            for field in self.pii_patterns:
                if field in redacted:
                    redacted[field] = f"[REDACTED-{hashlib.md5(str(redacted[field]).encode()).hexdigest()[:8]}]"

        return redacted

# ANTI-PATTERN: Retrieving all data then filtering (exposes PII)
class UnsafeCricketRAG:
    def retrieve_unsafe(self, query: str) -> str:
        # ❌ WRONG: Retrieves everything to LLM context
        all_docs = self.vector_db.semantic_search(query, top_k=100)
        # ❌ WRONG: Passes raw data including salaries, contact info
        context = "\n".join([doc['full_content'] for doc in all_docs])
        return self.llm.generate(f"Query: {query}\nContext: {context}")
        # ⚠️ RISK: LLM may echo sensitive data in response, logs expose PII
